const body = $input.first().json.body ?? $input.first().json;

const required = ['pr_id','requester_name','requester_email','description','category','amount','currency','cost_center'];
const missing = required.filter(f => !body[f]);

if (missing.length > 0) {
  throw new Error('Missing required fields: ' + missing.join(', '));
}

return [{
  json: {
    pr_id: body.pr_id,
    requester_name: body.requester_name,
    requester_email: body.requester_email,
    description: body.description,
    category: body.category,
    preferred_supplier: body.preferred_supplier ?? null,
    amount: parseFloat(body.amount),
    currency: body.currency ?? 'EUR',
    cost_center: body.cost_center,
    urgency: body.urgency ?? 'normal',
    required_by_date: body.required_by_date ?? null,
    received_at: new Date().toISOString()
  }
}];

const pr = $('Parse & Validate PR Fields').first().json;
const agentResponse = $input.first().json;

return [{
  json: {
    pr_id: pr.pr_id,
    received_at: pr.received_at,
    tier: agentResponse.tier,
    compliance_status: agentResponse.compliance_status,
    routing_decision: agentResponse.routing_decision,
    agent_reasoning: agentResponse.reasoning,
    logged_at: new Date().toISOString()
  }
}];
